import { ipcRenderer } from 'electron';
export function rendererSend(name, params) {
    ipcRenderer.send(name, params);
}
export function rendererSendSync(name, params) {
    ipcRenderer.sendSync(name, params);
}
export async function rendererInvoke(name, params) {
    return ipcRenderer.invoke(name, params);
}
export function rendererOn(name, listener) {
    ipcRenderer.on(name, (event, params) => {
        listener({ event, params });
    });
}
export function rendererOnce(name, listener) {
    ipcRenderer.once(name, (event, params) => {
        listener({ event, params });
    });
}
export const rendererOff = (name, listener) => {
    ipcRenderer.removeListener(name, listener);
};
export const rendererOffAll = (name) => {
    ipcRenderer.removeAllListeners(name);
};
